// Verificar que exista binario
if (!items[0].binary || !items[0].binary.data) {
  throw new Error("No binary data found in 'data'");
}

// Leer el archivo real desde filesystem
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');

// Convertir a base64
const base64 = buffer.toString('base64');

// Retornar limpio
return [
  {
    json: {
      base64: base64,
      mimeType: items[0].binary.data.mimeType
    }
  }
];

const input = $input.first();

// Obtener el archivo descargado
const downloadedFile = input.binary?.data;

if (!downloadedFile) {
  throw new Error('No se encontraron datos del archivo de audio');
}

// Retornar directamente sin anidar en "binary"
return {
  json: {},
  binary: {
    "audio/ogg": downloadedFile
  }
};

