const content = $json.message?.content || $json;
const partes = [];

for (let i = 1; i <= 12; i++) {
  const key = 'parte' + i;
  if (content[key] && content[key].trim() !== '') {
    partes.push({ json: { 
      text: content[key], 
      parte_num: i,
      sessionId: $json.sessionId || ''
    }});
  }
}

if (partes.length === 0) {
  const texto = $json.output || $json.text || '';
  if (texto) partes.push({ json: { 
    text: texto, 
    parte_num: 1, 
    sessionId: $json.sessionId || '' 
  }});
}

return partes;

