  texto = texto.replace(/[\u{2600}-\u{27BF}]/gu, '');
  texto = texto.replace(/[\u{FE00}-\u{FE0F}]/gu, '');
  texto = texto.replace(/[\u{1F1E0}-\u{1F1FF}]/gu, '');
  texto = texto.replace(/[\u{1F300}-\u{1FAFF}]/gu, '');
  texto = texto.replace(/[\u{2700}-\u{27BF}]/gu, '');
  texto = texto.replace(/[\u{1F900}-\u{1F9FF}]/gu, '');
  // Emojis compuestos con variación selector
  texto = texto.replace(/[\uFE0E\uFE0F]/g, '');
  // Eliminar combinaciones con ZWJ
  texto = texto.replace(/\u200D/g, ' ');
  // Eliminar símbolos de moneda y especiales que TTS lee raro (lista específica)
  texto = texto.replace(/[✅❌⭐🔥💎👑🎯🚀💰📊📱]/g, '');
  try {
    texto = texto.replace(/[\p{Emoji_Presentation}\p{Extended_Pictographic}]/gu, '');
  } catch(e) {}
  return texto;
}

// ════════════════════════════════════════
// INICIO DEL PROCESAMIENTO
// ════════════════════════════════════════

const item = $input.first();
let texto = item.json.text || item.json.output || '';

// ── PASO 1: Normalizar saltos de línea ──
texto = texto.replace(/\\n\\n/g, '. ');
texto = texto.replace(/\\n/g, ', ');
texto = texto.replace(/\n\n/g, '. ');
texto = texto.replace(/\n/g, ', ');

// ── PASO 2: Eliminar emojis PRIMERO ──
texto = eliminarEmojis(texto);

// ── PASO 3: Eliminar nombres de tools (Call_xxx, Get_xxx, etc.) ──
// Reemplaza cualquier palabra con formato snake_case o CamelCase_con_guiones
texto = texto.replace(/\bCall_[A-Za-z_]+\b/gi, '');
texto = texto.replace(/\bGet_[A-Za-z_]+\b/gi, '');
texto = texto.replace(/\bCalendar_[A-Za-z_]+\b/gi, '');
texto = texto.replace(/\bSheets_[A-Za-z_]+\b/gi, '');
texto = texto.replace(/\bGmail_[A-Za-z_]+\b/gi, '');

// ── PASO 4: Convertir SIGLAS en palabras pronunciables ──
// Esto es CRÍTICO: el TTS lee siglas en MAYÚSCULAS letra por letra
// Orden importante: las más largas primero

// Siglas de AID — pronunciar como palabras, no letra a letra
texto = texto.replace(/\bAID\b/g, 'Aid');           // A-I-D → Aid (como "Eyd")
texto = texto.replace(/\bAida\b/gi, 'Aida');         // mantener Aida igual

// Siglas de tecnología comunes en el prompt
texto = texto.replace(/\bTTS\b/g, 'sistema de voz');
texto = texto.replace(/\bAPI\b/gi, 'interfaz');
texto = texto.replace(/\bURL\b/gi, 'enlace');
texto = texto.replace(/\bCRM\b/g, 'sistema de clientes');
texto = texto.replace(/\bERP\b/g, 'sistema empresarial');
texto = texto.replace(/\bSEO\b/g, 'posicionamiento en Google');
texto = texto.replace(/\bPSE\b/g, 'pago en línea');
texto = texto.replace(/\bCOP\b/gi, 'pesos');
texto = texto.replace(/\bUSD\b/gi, 'dólares');
texto = texto.replace(/\bEUR\b/gi, 'euros');
texto = texto.replace(/\bIA\b/g, 'inteligencia artificial');
texto = texto.replace(/\bIVA\b/g, 'impuesto');
texto = texto.replace(/\bPDF\b/g, 'documento');
texto = texto.replace(/\bOCR\b/g, 'lectura de imágenes');
texto = texto.replace(/\bGPT\b/g, 'modelo de lenguaje');
texto = texto.replace(/\bLLM\b/g, 'modelo de inteligencia artificial');
texto = texto.replace(/\bVIP\b/g, 'premium');
texto = texto.replace(/\bB2B\b/g, 'empresa a empresa');
texto = texto.replace(/\bB2C\b/g, 'empresa a cliente');
texto = texto.replace(/\bROI\b/g, 'retorno de inversión');
texto = texto.replace(/\bKPI\b/g, 'indicador clave');
texto = texto.replace(/\bCTA\b/g, 'llamado a la acción');
texto = texto.replace(/\bQR\b/g, 'código');
texto = texto.replace(/\bFAQ\b/g, 'pregunta frecuente');
texto = texto.replace(/\bWA\b/g, 'WhatsApp');
texto = texto.replace(/\bIG\b/g, 'Instagram');
texto = texto.replace(/\bFB\b/g, 'Facebook');

// ── PASO 5: Limpiar markdown y formato ──
texto = texto.replace(/\*\*([^*]+)\*\*/g, '$1');
texto = texto.replace(/\*([^*]+)\*/g, '$1');
texto = texto.replace(/^[-•·✓✔]\s*/gm, '');
texto = texto.replace(/\s[-•·✓✔]\s/g, ', ');
texto = texto.replace(/#{1,6}\s*/g, '');
texto = texto.replace(/_{2,}/g, ' ');       // __ → espacio
texto = texto.replace(/_/g, ' ');            // _ restantes → espacio

// ── PASO 6: ELIMINAR SOLO SÍMBOLOS PROBLEMÁTICOS (NO quitar puntuación) ──
// Quitamos símbolos que el TTS suele leer raro, pero preservamos . , ? ! : ; -
// quitar corchetes, llaves y algunos símbolos especiales
texto = texto.replace(/[*#~`|\\^+=<>\{\}\[\]@°]/g, '');
// normalizar comillas tipográficas
texto = texto.replace(/[«»“”„‟]/g, '"');
// convertir guiones largos en coma para pausa natural (opcional)
texto = texto.replace(/[–—]/g, ',');
// eliminar ticks o marcas raras
texto = texto.replace(/[✓✔✗✘]/g, '');
// flechas y símbolos direccionales eliminados
texto = texto.replace(/[→←↑↓↔]/g, '');
// números encircled u otros bullets
texto = texto.replace(/[①②③④⑤]/g, '');
// viñetas y puntos no estándar
texto = texto.replace(/[•·◦▪▫]/g, ',');
// convertir signos de apertura invertidos a nada (dejamos el signo de cierre normal)
texto = texto.replace(/[¿¡]/g, '');
// NO eliminar . , ? ! : ;  — los conservamos para que TTS haga pausas y entonación

// ── PASO 7: Eliminar el símbolo $ (el TTS puede leerlo como "dólar") ──
texto = texto.replace(/\$/g, '');

// ── PASO 8: Convertir horas ──
texto = texto.replace(/(\d{1,2}):(\d{2})\s*(AM|PM|am|pm)/g, (_, h, m, p) => {
  const hora = parseInt(h), min = parseInt(m);
  const momento = p.toLowerCase() === 'am' ? 'de la mañana' : hora < 6 ? 'de la madrugada' : 'de la noche';
  if (min === 0)  return 'las ' + numPalabras(hora) + ' ' + momento;
  if (min === 30) return 'las ' + numPalabras(hora) + ' y media ' + momento;
  if (min === 15) return 'las ' + numPalabras(hora) + ' y cuarto ' + momento;
  if (min === 45) return 'las ' + numPalabras(hora+1) + ' menos cuarto';
  return 'las ' + numPalabras(hora) + ' y ' + numPalabras(min) + ' ' + momento;
});

texto = texto.replace(/(\d{1,2}):(\d{2})/g, (_, h, m) => {
  const hora = parseInt(h), min = parseInt(m);
  const momento = hora < 12 ? 'de la mañana' : hora < 18 ? 'de la tarde' : 'de la noche';
  const h12 = hora > 12 ? hora - 12 : hora;
  if (min === 0)  return 'las ' + numPalabras(h12) + ' ' + momento;
  if (min === 30) return 'las ' + numPalabras(h12) + ' y media ' + momento;
  if (min === 15) return 'las ' + numPalabras(h12) + ' y cuarto ' + momento;
  if (min === 45) return 'las ' + numPalabras(h12+1) + ' menos cuarto';
  return 'las ' + numPalabras(h12) + ' y ' + numPalabras(min) + ' ' + momento;
});

// ── PASO 9: Convertir unidades y medidas ──
texto = texto.replace(/(\d+(?:\.\d+)?)\s*°C/gi, (_, n) => numPalabras(parseFloat(n)) + ' grados centígrados');
texto = texto.replace(/(\d+(?:\.\d+)?)\s*°F/gi, (_, n) => numPalabras(parseFloat(n)) + ' grados fahrenheit');
texto = texto.replace(/(\d+(?:\.\d+)?)\s*km\/h/gi, (_, n) => numPalabras(parseFloat(n)) + ' kilómetros por hora');
texto = texto.replace(/(\d+)\s*%/g, (_, n) => numPalabras(parseInt(n)) + ' por ciento');
texto = texto.replace(/(\d+)\s*km\b/gi, (_, n) => numPalabras(parseInt(n)) + ' kilómetros');
texto = texto.replace(/(\d+)\s*min\b/gi, (_, n) => numPalabras(parseInt(n)) + ' minutos');
texto = texto.replace(/(\d+)\s*h\b/gi, (_, n) => numPalabras(parseInt(n)) + ' horas');

// ── PASO 10: Teléfonos colombianos ──
texto = texto.replace(/\b(3\d{2}[\s\-]?\d{7})\b/g, (m) => leerTelefonoColombia(m));

// ── PASO 11: Números grandes con puntos (1.500.000 → un millón quinientos mil) ──
// Proteger años primero
texto = texto.replace(/\b(20\d{2})\b/g, '__AÑO_$1__');
texto = texto.replace(/\b(\d{1,3})(\.\d{3})+\b/g, m => numPalabras(parseInt(m.replace(/\./g, ''))));
texto = texto.replace(/__AÑO_(\d{4})__/g, '$1');

// ── PASO 12: Limpiar puntuación residual ──
// compactar puntos múltiples, comas múltiples y asegurar espacio después de puntuación principal
texto = texto.replace(/\.{2,}/g, '.');
texto = texto.replace(/,{2,}/g, ',');
// asegurar espacio después de .,?,!,;:
texto = texto.replace(/([.!?;:])\s*/g, '$1 ');
texto = texto.replace(/\s*:\s*/g, ': ');
texto = texto.replace(/  +/g, ' ').trim();

// ── PASO 13: Pausas naturales para hablar más fluido ──
texto = texto.replace(/\bpero\b/gi, ', pero');
texto = texto.replace(/\bsin embargo\b/gi, ', sin embargo,');
texto = texto.replace(/\bademás\b/gi, ', además,');
texto = texto.replace(/\bpor lo tanto\b/gi, ', por lo tanto,');

// ── PASO 14: Eliminar muletillas al inicio que suenan raro en voz ──
texto = texto.replace(/^ay,?\s*/i, '');
texto = texto.replace(/^ay no,?\s*/i, '');
texto = texto.replace(/^ay qué,?\s*/i, '');
texto = texto.replace(/^ay que,?\s*/i, '');
texto = texto.replace(/^eh,?\s*/i, '');
texto = texto.replace(/^um,?\s*/i, '');

// ── PASO 15: Verificar longitud máxima del TTS ──
if (texto.length > 2000) {
  texto = texto.substring(0, 2000) + '. El resto está disponible por escrito.';
}

// ── PASO 16: Limpieza final de espacios ──
texto = texto.replace(/\s+/g, ' ').trim();

// Envolver en SSML para más naturalidad
const ssml = `<speak version="1.0" xmlns="http://www.w3.org/2001/10/synthesis" 
  xmlns:mstts="http://www.w3.org/2001/mstts" xml:lang="es-CO">
  <voice name="es-CO-SalomeNeural">
    <mstts:express-as style="customerservice" styledegree="1.5">
      <prosody rate="-5%" pitch="+2%">
        ${texto}
      </prosody>
    </mstts:express-as>
  </voice>
</speak>`;

// ✅ CÓDIGO CORREGIDO
const idioma_detectado = (() => {
  // Español: único con ñ
  if (/[ñÑ]/.test(texto)) return 'es';
  // Inglés: solo ASCII
  if (/^[a-zA-Z0-9\s.,!?'"\-:;()]+$/.test(texto)) return 'en';
  // Portugués: únicos ã, õ, ç
  if (/[ãõÃÕ]/.test(texto)) return 'pt';
  // Francés: únicos œ, æ, û, ù precede a vocales típicas
  if (/[œæùûÙÛŒÆ]/.test(texto)) return 'fr';
  // Italiano: à, è, ì, ò específicos
  if (/[àèìòÀÈÌÒ]/.test(texto)) return 'it';
  // Default: español
  return 'es';
})();

return [{ json: { text: texto, idioma_detectado } }];
